import React, { useState, useEffect, useRef, useCallback } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  ScrollView,
  StyleSheet,
  Animated,
  Linking,
  BackHandler,
  Alert,
} from 'react-native';
import * as Location from 'expo-location';
import { useIncidentStore } from '../store';
import {
  SafeAreaContainer,
  Header,
  Button,
  EmergencyCard,
  GoldenHourTimer,
  LocationBar,
  AlertFamilyButton,
  FirstAidSteps,
  PumpAlertBanner,
  KmMarkerModal,
  ResultTab,
  Colors,
} from '../components/Layout';

// ─── MOCK DATA helpers ───────────────────────────────────────────────────────
const makeMockHospitals = (severity: string) => {
  if (severity === 'critical') {
    return [
      { name: 'City Trauma Centre', distance: '1.8 km', phone: '080-22221111', type: 'Trauma' },
      { name: 'District Hospital', distance: '3.2 km', phone: '080-22335566', type: 'Hospital' },
    ];
  }
  if (severity === 'moderate') {
    return [
      { name: 'General Hospital', distance: '2.1 km', phone: '080-44112233', type: 'Hospital' },
      { name: 'Sunrise Clinic', distance: '4.0 km', phone: '080-55667788', type: 'Clinic' },
    ];
  }
  return [
    { name: 'Sunrise Clinic', distance: '1.2 km', phone: '080-11223344', type: 'Clinic' },
    { name: 'LifeCare Medical', distance: '2.6 km', phone: '080-99887766', type: 'Clinic' },
  ];
};

const MOCK_FIRE_STATIONS = [
  { name: 'Central Fire Station', distance: '2.0 km', phone: '101' },
  { name: 'North Fire Brigade', distance: '3.5 km', phone: '101' },
];

const MOCK_TOWING = [
  { name: 'Highway Towing Co.', distance: '1.2 km', phone: '98765 43210' },
  { name: 'QuickTow Services', distance: '2.8 km', phone: '90000 11111' },
];
const MOCK_PUNCTURE = [
  { name: 'Rapid Tyre Repair', distance: '0.8 km', phone: '88888 00000' },
  { name: 'City Tyre Shop', distance: '2.1 km', phone: '77777 22222' },
];
const MOCK_PUMPS = [
  { name: 'HP Fuel Station', distance: '0.5 km', phone: '99999 88888' },
  { name: 'Indian Oil', distance: '1.4 km', phone: '11111 77777' },
];
const MOCK_SHOWROOMS = [
  { name: 'Maruti Suzuki Service', distance: '3.0 km', phone: '44444 66666' },
  { name: 'Tata Motors Workshop', distance: '4.2 km', phone: '33333 55555' },
];

const MOCK_POLICE = { name: 'Police Control Room', distance: '2.5 km', phone: '100' };
const MOCK_PUMP = { name: 'Highway Fuel Station', distance: '0.9 km', phone: '98765 11111' };
const MOCK_NDRF = { name: 'NDRF Rescue Control', distance: '5.0 km', phone: '1078' };

const callNumber = (num: string) => Linking.openURL(`tel:${num.replace(/\s/g, '')}`);
const openMaps = (name: string) => Linking.openURL(`https://www.google.com/maps/search/${encodeURIComponent(name)}`);

// ─── TRIAGE SCREEN ───────────────────────────────────────────────────────────
const TRIAGE_QUESTIONS = [
  { id: 'q1', text: 'Is anyone unconscious or unresponsive?' },
  { id: 'q2', text: 'Is there heavy or uncontrolled bleeding?' },
  { id: 'q3', text: 'Is anyone trapped in the vehicle?' },
];

export const TriageScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const [currentQ, setCurrentQ] = useState(0);
  const [answers, setAnswers] = useState<boolean[]>([]);
  const setTriageLevel = useIncidentStore((s) => s.setTriageLevel);
  const slideAnim = useRef(new Animated.Value(0)).current;

  const animateIn = () => {
    slideAnim.setValue(40);
    Animated.spring(slideAnim, { toValue: 0, useNativeDriver: true, tension: 80, friction: 12 }).start();
  };

  const handleAnswer = (yes: boolean) => {
    const newAnswers = [...answers, yes];
    setAnswers(newAnswers);

    if (currentQ < TRIAGE_QUESTIONS.length - 1) {
      setCurrentQ(currentQ + 1);
      animateIn();
    } else {
      // Calculate severity
      const yesCount = newAnswers.filter(Boolean).length;
      if (yesCount >= 2) setTriageLevel('critical');
      else if (yesCount === 1) setTriageLevel('moderate');
      else setTriageLevel('minor');
      navigation.navigate('MedicalDetails');
    }
  };

  const q = TRIAGE_QUESTIONS[currentQ];

  return (
    <SafeAreaContainer>
      {/* Red header bar */}
      <View style={es.triageHeader}>
        <TouchableOpacity onPress={() => navigation.goBack()} hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}>
          <Text style={{ color: '#fff', fontSize: 24 }}>←</Text>
        </TouchableOpacity>
        <Text style={es.triageHeaderText}>Quick Check</Text>
        <View style={{ width: 24 }} />
      </View>

      {/* Progress dots */}
      <View style={es.progressDots}>
        {TRIAGE_QUESTIONS.map((_, i) => (
          <View
            key={i}
            style={[es.progressDot, i < currentQ && es.progressDotDone, i === currentQ && es.progressDotActive]}
          />
        ))}
      </View>

      <View style={es.triageContent}>
        <Text style={es.triageStep}>Question {currentQ + 1} of {TRIAGE_QUESTIONS.length}</Text>

        <Animated.View style={{ transform: [{ translateY: slideAnim }] }}>
          <Text style={es.triageQuestion}>{q.text}</Text>
        </Animated.View>

        <View style={es.triageButtons}>
          <TouchableOpacity style={es.yesBtn} onPress={() => handleAnswer(true)} activeOpacity={0.8}>
            <Text style={es.yesBtnText}>YES</Text>
          </TouchableOpacity>
          <TouchableOpacity style={es.noBtn} onPress={() => handleAnswer(false)} activeOpacity={0.8}>
            <Text style={es.noBtnText}>NO</Text>
          </TouchableOpacity>
        </View>
      </View>
    </SafeAreaContainer>
  );
};

// ─── MEDICAL EMERGENCY SCREEN ─────────────────────────────────────────────────
export const MedicalEmergencyScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const { triageLevel, location, setLocation, emergencyContacts } = useIncidentStore();
  const [placeName, setPlaceName] = useState('');
  const [kmModalVisible, setKmModalVisible] = useState(false);
  const [familyAlerted, setFamilyAlerted] = useState(false);
  const [pumpAlerted, setPumpAlerted] = useState(false);
  const [timerStart] = useState(Date.now());

  const severity = triageLevel || 'minor';
  const hospitals = makeMockHospitals(severity);

  const severityLabel = { critical: 'TRAUMA CENTRE', moderate: 'HOSPITAL EMERGENCY', minor: 'CLINIC' }[severity];
  const accentColor = { critical: Colors.red, moderate: Colors.orange, minor: Colors.blue }[severity];

  useEffect(() => {
    // Auto-get location on mount
    (async () => {
      try {
        const { status } = await Location.requestForegroundPermissionsAsync();
        if (status === 'granted') {
          const loc = await Location.getCurrentPositionAsync({ accuracy: Location.Accuracy.Balanced });
          setLocation(loc.coords.latitude, loc.coords.longitude);
          setPlaceName(`${loc.coords.latitude.toFixed(4)}, ${loc.coords.longitude.toFixed(4)}`);
        }
      } catch {}
    })();

    // Auto-dial on trauma
    if (severity === 'critical') {
      setTimeout(() => {
        Alert.alert(
          '🚑 Calling Ambulance',
          'Dialling 108 for an ambulance now.',
          [
            { text: 'Call 108', onPress: () => callNumber('108') },
            { text: 'Cancel', style: 'cancel' },
          ]
        );
      }, 1000);
    }
  }, []);

  const firstAidSteps = {
    critical: ["Don't move the victim unless there's fire risk", 'Apply firm pressure to any bleeding', 'Keep them warm and still — help is coming'],
    moderate: ['Keep the person calm and still', 'Check for visible injuries', 'Do not give food or water'],
    minor: ['Move to safety away from traffic', 'Sit down and rest', 'Call the clinic for guidance'],
  }[severity];

  return (
    <SafeAreaContainer>
      <GoldenHourTimer startTime={timerStart} />
      <Header title={`Medical — ${severityLabel}`} onBack={() => navigation.goBack()} color={accentColor} />

      {pumpAlerted && <PumpAlertBanner pumpName={MOCK_PUMP.name} />}

      <ScrollView contentContainerStyle={es.content}>
        <LocationBar placeName={placeName} onKmMarkerPress={() => setKmModalVisible(true)} />

        {severity === 'critical' && (
          <View style={[es.autoDial, { backgroundColor: accentColor }]}>
            <Text style={es.autoDialText}>🚑 Calling ambulance — 108</Text>
          </View>
        )}

        <Text style={es.sectionLabel}>Nearest {severityLabel}s</Text>
        {hospitals.map((h, i) => (
          <EmergencyCard
            key={i}
            name={h.name}
            distance={h.distance}
            phone={h.phone}
            accentColor={accentColor}
            onCall={() => callNumber(h.phone)}
            onNavigate={() => openMaps(h.name)}
          />
        ))}

        <Text style={es.sectionLabel}>Police</Text>
        <EmergencyCard
          name={MOCK_POLICE.name}
          distance={MOCK_POLICE.distance}
          phone={MOCK_POLICE.phone}
          accentColor={Colors.slate}
          onCall={() => callNumber(MOCK_POLICE.phone)}
          onNavigate={() => openMaps(MOCK_POLICE.name)}
        />

        <Text style={es.sectionLabel}>Nearest Petrol Pump</Text>
        <EmergencyCard
          name={MOCK_PUMP.name}
          distance={MOCK_PUMP.distance}
          phone={MOCK_PUMP.phone}
          onCall={() => callNumber(MOCK_PUMP.phone)}
          onNavigate={() => openMaps(MOCK_PUMP.name)}
        />
        {!pumpAlerted && (
          <Button title="⛽ Alert Petrol Pump" onPress={() => setPumpAlerted(true)} variant="outline" style={{ marginBottom: 8 }} />
        )}

        <FirstAidSteps steps={firstAidSteps} />
        <AlertFamilyButton sent={familyAlerted} onPress={() => setFamilyAlerted(true)} />

        <TouchableOpacity
          style={es.bystanderLink}
          onPress={() => navigation.navigate('IncidentMap', { incidentId: 'inc_' + Date.now() })}
        >
          <Text style={es.bystanderLinkText}>👁 I'm a bystander here →</Text>
        </TouchableOpacity>
      </ScrollView>

      <KmMarkerModal
        visible={kmModalVisible}
        onClose={() => setKmModalVisible(false)}
        onResolve={(hw, km) => {
          setPlaceName(`${hw}, KM ${km}`);
          setKmModalVisible(false);
        }}
      />
    </SafeAreaContainer>
  );
};

// ─── EVACUATION GUIDE SCREEN ─────────────────────────────────────────────────
const EVAC_STEPS = [
  { icon: '🔑', text: 'TURN OFF IGNITION', sub: 'Cut the fuel supply immediately.' },
  { icon: '🏃', text: 'GET EVERYONE OUT', sub: 'All passengers out now. Leave everything.' },
  { icon: '🚫', text: 'DO NOT open the bonnet', sub: 'Oxygen feeds the fire. Stay away.' },
  { icon: '📞', text: 'Call 101 — Fire Brigade', sub: 'Give your location and stay clear.' },
];

export const EvacuationGuideScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [seconds, setSeconds] = useState(90);
  const timerRef = useRef<any>(null);
  const progress = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    timerRef.current = setInterval(() => {
      setSeconds((s) => {
        if (s <= 1) {
          clearInterval(timerRef.current);
          navigation.replace('EmergencyFire');
          return 0;
        }
        return s - 1;
      });
    }, 1000);

    // Auto-advance steps every 15s
    const stepTimer = setInterval(() => {
      setCurrentStep((prev) => Math.min(prev + 1, EVAC_STEPS.length - 1));
    }, 15000);

    return () => {
      clearInterval(timerRef.current);
      clearInterval(stepTimer);
    };
  }, []);

  return (
    <View style={[es.evacBg, { flex: 1 }]}>
      {/* Timer */}
      <View style={es.evacTimer}>
        <Text style={es.evacTimerLabel}>Evacuate in</Text>
        <Text style={es.evacTimerNum}>{seconds}s</Text>
      </View>

      <ScrollView contentContainerStyle={es.evacContent}>
        {EVAC_STEPS.map((step, i) => (
          <View
            key={i}
            style={[
              es.evacStep,
              i === currentStep && es.evacStepActive,
              i < currentStep && es.evacStepDone,
            ]}
          >
            <Text style={es.evacStepIcon}>{step.icon}</Text>
            <View style={{ flex: 1 }}>
              <Text style={[es.evacStepText, i < currentStep && { opacity: 0.5 }]}>{step.text}</Text>
              <Text style={es.evacStepSub}>{step.sub}</Text>
            </View>
            {i < currentStep && <Text style={{ color: 'rgba(255,255,255,0.7)', fontSize: 22 }}>✓</Text>}
          </View>
        ))}

        {currentStep < EVAC_STEPS.length - 1 && (
          <TouchableOpacity
            style={es.evacNextBtn}
            onPress={() => setCurrentStep((p) => Math.min(p + 1, EVAC_STEPS.length - 1))}
          >
            <Text style={es.evacNextText}>Done, next step →</Text>
          </TouchableOpacity>
        )}
      </ScrollView>

      {/* Persistent bottom button */}
      <TouchableOpacity style={es.evacBottomBtn} onPress={() => navigation.navigate('EmergencyFire')}>
        <Text style={es.evacBottomBtnText}>🚒 Show nearby fire brigade</Text>
      </TouchableOpacity>
    </View>
  );
};

// ─── FIRE EMERGENCY SCREEN ────────────────────────────────────────────────────
export const FireEmergencyScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const [familyAlerted, setFamilyAlerted] = useState(false);

  return (
    <SafeAreaContainer>
      <Header title="🔥 Fire Emergency" onBack={() => navigation.navigate('EvacuationGuide')} color={Colors.orange} />
      <ScrollView contentContainerStyle={es.content}>
        {/* Warning card */}
        <View style={es.fireWarning}>
          <Text style={es.fireWarningTitle}>⚠️ DO NOT use water on fuel fires</Text>
          <Text style={es.fireWarningText}>Water spreads fuel fires. Use sand or a fire extinguisher only.</Text>
        </View>

        <Text style={es.sectionLabel}>Fire Brigade</Text>
