// ─── BREAKDOWN SCREEN ─────────────────────────────────────────────────────────
const BREAKDOWN_TABS = ['Towing', 'Puncture', 'Petrol Pumps', 'Showrooms'];
const BREAKDOWN_DATA = [MOCK_TOWING, MOCK_PUNCTURE, MOCK_PUMPS, MOCK_SHOWROOMS];

export const BreakdownScreen: React.FC<{ navigation: any; route: any }> = ({ navigation, route }) => {
  const defaultTab = route?.params?.params?.defaultTab ?? 0;
  const [activeTab, setActiveTab] = useState(defaultTab);
  const [placeName, setPlaceName] = useState('');
  const [kmModalVisible, setKmModalVisible] = useState(false);
  const [pumpAlerted, setPumpAlerted] = useState(false);

  useEffect(() => {
    (async () => {
      try {
        const { status } = await Location.requestForegroundPermissionsAsync();
        if (status === 'granted') {
          const loc = await Location.getCurrentPositionAsync({ accuracy: Location.Accuracy.Balanced });
          setPlaceName(`${loc.coords.latitude.toFixed(4)}, ${loc.coords.longitude.toFixed(4)}`);
        }
      } catch {}
    })();
  }, []);

  const results = BREAKDOWN_DATA[activeTab];
  const accentColor = [Colors.blue, Colors.blue, Colors.purple, Colors.blue][activeTab];

  return (
    <SafeAreaContainer>
      <Header title="🔧 Breakdown / Fuel" onBack={() => navigation.goBack()} />
      <ScrollView contentContainerStyle={es.content}>
        <LocationBar placeName={placeName} onKmMarkerPress={() => setKmModalVisible(true)} />
        {pumpAlerted && <PumpAlertBanner pumpName={MOCK_PUMP.name} />}

        <ResultTab tabs={BREAKDOWN_TABS} activeIndex={activeTab} onTabChange={setActiveTab} />

        {results.map((r, i) => (
          <EmergencyCard
            key={i}
            name={r.name}
            distance={r.distance}
            phone={r.phone}
            accentColor={accentColor}
            onCall={() => callNumber(r.phone)}
            onNavigate={() => openMaps(r.name)}
          />
        ))}

        {activeTab === 2 && !pumpAlerted && (
          <Button title="⛽ Alert Nearest Pump" onPress={() => setPumpAlerted(true)} variant="outline" />
        )}
      </ScrollView>
      <KmMarkerModal
        visible={kmModalVisible}
        onClose={() => setKmModalVisible(false)}
        onResolve={(hw, km) => { setPlaceName(`${hw}, KM ${km}`); setKmModalVisible(false); }}
      />
    </SafeAreaContainer>
  );
};

