// ─── SILENT SOS SCREEN ───────────────────────────────────────────────────────
export const SilentSOSScreen: React.FC<{ navigation: any }> = ({ navigation }) => {
  const tapCount = useRef(0);
  const tapTimer = useRef<any>(null);

  useEffect(() => {
    // Disable Android hardware back
    const sub = BackHandler.addEventListener('hardwareBackPress', () => true);
    return () => sub.remove();
  }, []);

  const handleTripleTap = () => {
    tapCount.current += 1;
    if (tapTimer.current) clearTimeout(tapTimer.current);

    if (tapCount.current >= 3) {
      tapCount.current = 0;
      // Restore and go home
      navigation.navigate('HomeMain');
    } else {
      tapTimer.current = setTimeout(() => { tapCount.current = 0; }, 2000);
    }
  };

  return (
    <View style={es.sosBg}>
      {/* Nearly invisible — this screen appears as if the device is off */}
      <TouchableOpacity
        style={es.sosTapZone}
        onPress={handleTripleTap}
        activeOpacity={1}
      />
      {/* Tiny barely-visible indicator for demo purposes */}
      <View style={es.sosHint}>
        <Text style={es.sosHintText}>SOS Active · Triple-tap corner to cancel</Text>
      </View>
    </View>
  );
};

